import React, { useEffect, useState } from "react";
import axios from "axios";
import {
  Chart as ChartJS,
  CategoryScale,
  LinearScale,
  BarElement,
  PointElement,
  LineElement,
  Title,
  Tooltip,
  Legend,
} from "chart.js";
import { Line, Bar } from "react-chartjs-2";
import "./PriceAnalytics.css";

ChartJS.register(
  CategoryScale,
  LinearScale,
  BarElement,
  PointElement,
  LineElement,
  Title,
  Tooltip,
  Legend
);

const API_BASE = "http://localhost:7000/api";

export default function PriceAnalytics() {
  const [range, setRange] = useState("weekly");
  const [loading, setLoading] = useState(false);

  const [productList, setProductList] = useState([]);
  const [categoryList, setCategoryList] = useState([]);
  const [selectedProduct, setSelectedProduct] = useState("");
  const [selectedCategory, setSelectedCategory] = useState("");

  const [productData, setProductData] = useState([]);
  const [categoryData, setCategoryData] = useState([]);

  // 🟢 Fetch dropdown data (Products + Categories)
  useEffect(() => {
    const fetchLists = async () => {
      try {
        const [productsRes, catsRes] = await Promise.all([
          axios.get(`${API_BASE}/prices`),
          axios.get(`${API_BASE}/categories`),
        ]);
        setProductList(productsRes.data || []);
        setCategoryList(catsRes.data || []);
      } catch (err) {
        console.error("Error fetching lists:", err);
      }
    };
    fetchLists();
  }, []);

  // 🟢 Fetch price trends dynamically
  useEffect(() => {
    const fetchTrends = async () => {
      setLoading(true);
      try {
        const [prodRes, catRes] = await Promise.all([
          axios.get(
            `${API_BASE}/price-report/trends?type=product&range=${range}${
              selectedProduct ? `&filter=${selectedProduct}` : ""
            }`
          ),
          axios.get(
            `${API_BASE}/price-report/trends?type=category&range=${range}${
              selectedCategory ? `&filter=${selectedCategory}` : ""
            }`
          ),
        ]);

        setProductData(prodRes.data || []);
        setCategoryData(catRes.data || []);
      } catch (err) {
        console.error("Error fetching trends:", err);
        setProductData([]);
        setCategoryData([]);
      } finally {
        setLoading(false);
      }
    };
    fetchTrends();
  }, [range, selectedProduct, selectedCategory]);

  // 🟢 Line Chart (Product-wise)
  const lineChartData = {
    labels:
      productData.length > 0
        ? [...new Set(productData.flatMap((d) => d.prices.map((p) => p.date)))].sort()
        : [],
    datasets: productData.flatMap((p, i) => [
      {
        label: `${p._id} - Avg Price`,
        data: p.prices.map((pr) => pr.avgPrice),
        borderColor: `hsl(${i * 50}, 70%, 50%)`,
        backgroundColor: `hsla(${i * 50}, 70%, 60%, 0.25)`,
        tension: 0.4,
      },
      {
        label: `${p._id} - Difference`,
        data: p.prices.map((pr) => pr.difference || 0),
        borderColor: `hsl(${i * 50 + 180}, 70%, 50%)`,
        backgroundColor: `hsla(${i * 50 + 180}, 70%, 60%, 0.25)`,
        borderDash: [4, 4],
        tension: 0.4,
      },
    ]),
  };

  // 🟢 Bar Chart (Category-wise)
  const barChartData = {
    labels:
      categoryData.length > 0
        ? [...new Set(categoryData.flatMap((d) => d.prices.map((p) => p.date)))].sort()
        : [],
    datasets: categoryData.flatMap((c, i) => [
      {
        label: `${c._id} - Avg Price`,
        data: c.prices.map((pr) => pr.avgPrice),
        backgroundColor: `hsla(${i * 60}, 70%, 60%, 0.7)`,
      },
      {
        label: `${c._id} - Difference`,
        data: c.prices.map((pr) => pr.difference || 0),
        backgroundColor: `hsla(${i * 60 + 180}, 70%, 60%, 0.7)`,
      },
    ]),
  };

  return (
    <div className="analytics-container">
      <h2 className="analytics-title">📊 Price Analytics Dashboard</h2>

      {/* Filters */}
      <div className="filter-row">
        <div className="filter-group">
          <label>📅 Range:</label>
          <select value={range} onChange={(e) => setRange(e.target.value)}>
            <option value="weekly">Last 30 Days (Weekly)</option>
            <option value="monthly">Last 6 Months (Monthly)</option>
          </select>
        </div>
      </div>

      {/* Graphs */}
      {loading ? (
        <p className="no-data">Loading data...</p>
      ) : (
        <div className="chart-grid">
          {/* Product Chart */}
          <div className="chart-card">
            <div className="chart-header">
              <h3>📈 Product Price Trends</h3>
              <select
                className="dropdown-select"
                value={selectedProduct}
                onChange={(e) => setSelectedProduct(e.target.value)}
              >
                <option value="">All Products</option>
                {productList.map((p) => (
                  <option key={p._id} value={p.name}>
                    {p.name}
                  </option>
                ))}
              </select>
            </div>
            <div className="chart-container">
              {lineChartData.labels.length > 0 ? (
                <Line
                  data={lineChartData}
                  options={{
                    responsive: true,
                    maintainAspectRatio: false,
                    plugins: {
                      legend: { position: "bottom" },
                      title: {
                        display: true,
                        text: "Average & Difference Trends (Product-wise)",
                      },
                    },
                    scales: {
                      y: { beginAtZero: true, title: { display: true, text: "Price (₹)" } },
                    },
                  }}
                />
              ) : (
                <p className="no-data">No product data available</p>
              )}
            </div>
          </div>

          {/* Category Chart */}
          <div className="chart-card">
            <div className="chart-header">
              <h3>📉 Category Price Trends</h3>
              <select
                className="dropdown-select"
                value={selectedCategory}
                onChange={(e) => setSelectedCategory(e.target.value)}
              >
                <option value="">All Categories</option>
                {categoryList.map((c) => (
                  <option key={c._id} value={c.name}>
                    {c.name}
                  </option>
                ))}
              </select>
            </div>
            <div className="chart-container">
              {barChartData.labels.length > 0 ? (
                <Bar
                  data={barChartData}
                  options={{
                    responsive: true,
                    maintainAspectRatio: false,
                    plugins: {
                      legend: { position: "bottom" },
                      title: {
                        display: true,
                        text: "Average & Difference (Category-wise)",
                      },
                    },
                    scales: {
                      y: { beginAtZero: true, title: { display: true, text: "Price (₹)" } },
                    },
                  }}
                />
              ) : (
                <p className="no-data">No category data available</p>
              )}
            </div>
          </div>
        </div>
      )}
    </div>
  );
}
